+    public void add(TimePeriodValue item) {
+        if (item == null) {
+            throw new IllegalArgumentException("Null item not allowed.");
+        }
+        this.data.add(item);
+        updateBounds(item.getPeriod(), this.data.size() - 1);
+        fireSeriesChanged();
